112	                         const unsigned int kv_strides_2, const unsigned int kv_strides_1,
113	                         const unsigned int kv_strides_0, void* q_ptr, const void* k_ptr,
114	                         const void* v_ptr, void* o_ptr, void* partial_o_ptr,
115	                         tma::cudaTmaDesc* tma_desc_q_array, tma::cudaTmaDesc* tma_desc_k,
116	                         tma::cudaTmaDesc* tma_desc_v, tma::cudaTmaDesc* tma_desc_o_array,
117	                         tma::cudaTmaDesc* tma_desc_partial_o_array, int64_t* batch_strides_dev) {
118	  const int tid = threadIdx.x;
119	
120	  constexpr unsigned int DIMS_QKV = 4;
121	  constexpr unsigned int BYTES_PER_ELEMENT = 2;
122	
123	  std::array<uint32_t, DIMS_QKV> tensor_traversal_stride_qkv = {1, 1, 1, 1};
124	  std::array<uint32_t, DIMS_QKV> tensor_box_size_qo = {64, 1, 1, 1};
125	  std::array<uint32_t, DIMS_QKV> tensor_box_size_kv = {64, std::min(tile_n_1, page_size), 1, 1};
126	  std::array<uint32_t, DIMS_QKV> tensor_box_size_partial_o = {32, 1, 1, 1};
127	
128	  std::array<uint32_t, DIMS_QKV> tensor_size_qo = {d, 1 /* s_qo */, h_qo, b};
129	  std::array<uint32_t, DIMS_QKV> tensor_size_kv = {d, page_size, h_kv, total_num_pages};
130	
131	  std::array<uint64_t, DIMS_QKV - 1> tensor_stride_qo = {h_qo * d * BYTES_PER_ELEMENT,
132	                                                         d * BYTES_PER_ELEMENT, 0};
133	  std::array<uint64_t, DIMS_QKV - 1> tensor_stride_kv = {kv_strides_2 * (BYTES_PER_ELEMENT),
134	                                                         kv_strides_1 * (BYTES_PER_ELEMENT),
135	                                                         kv_strides_0 * (BYTES_PER_ELEMENT)};
136	
137	  std::array<uint32_t, DIMS_QKV> tensor_size_partial_o = {d, split_factor, h_qo, b};
138	  std::array<uint64_t, DIMS_QKV - 1> tensor_stride_partial_o = {
139	      h_qo * d * b * sizeof(float), d * b * sizeof(float), d * h_qo * sizeof(float)};
140	
141	  tma::cudaSetTmaTileDescriptor(
142	      reinterpret_cast<tma::cudaTmaDesc*>(tma_desc_k), k_ptr, DIMS_QKV, tensor_size_kv.data(),
143	      tensor_stride_kv.data(), tensor_traversal_stride_qkv.data(), tensor_box_size_kv.data(),
144	      tma::cudaTmaDescFormat::BF16_RN, tma::cudaTmaDescSwizzle::SWIZZLE_128B);
145	
146	  tma::cudaSetTmaTileDescriptor(
147	      reinterpret_cast<tma::cudaTmaDesc*>(tma_desc_v), v_ptr, DIMS_QKV, tensor_size_kv.data(),
148	      tensor_stride_kv.data(), tensor_traversal_stride_qkv.data(), tensor_box_size_kv.data(),
149	      tma::cudaTmaDescFormat::BF16_RN, tma::cudaTmaDescSwizzle::SWIZZLE_128B);
150	
151	  int64_t batch_offset_qo = 0;
152	  int64_t batch_offset_partial_o = 0;
153	#pragma unroll 1
154	  for (int i = 0; i < b; ++i) {
155	    batch_strides_dev[i] = batch_offset_qo;
156	    uint16_t* per_batch_q_ptr =
157	        reinterpret_cast<uint16_t*>(static_cast<std::byte*>(q_ptr) + batch_offset_qo);
158	    uint16_t* per_batch_out_ptr =
159	        reinterpret_cast<uint16_t*>(static_cast<std::byte*>(o_ptr) + batch_offset_qo);
160	    // The two below comes from half
161	    float* per_batch_partial_o_ptr =
162	        reinterpret_cast<float*>(static_cast<std::byte*>(partial_o_ptr) + (batch_offset_partial_o));
163	
164	    tma::cudaTmaDesc desc_q;
165	    tma::cudaTmaDesc desc_o;
166	    tma::cudaTmaDesc desc_partial_o;
167	
168	    tma::cudaSetTmaTileDescriptor(&desc_q, (void*)per_batch_q_ptr, DIMS_QKV, tensor_size_qo.data(),
169	                                  tensor_stride_qo.data(), tensor_traversal_stride_qkv.data(),
170	                                  tensor_box_size_qo.data(), tma::cudaTmaDescFormat::BF16_RN,
171	                                  tma::cudaTmaDescSwizzle::SWIZZLE_128B);
172	
173	    tma::cudaSetTmaTileDescriptor(
174	        &desc_o, (void*)per_batch_out_ptr, DIMS_QKV, tensor_size_qo.data(), tensor_stride_qo.data(),
175	        tensor_traversal_stride_qkv.data(), tensor_box_size_qo.data(),
176	        tma::cudaTmaDescFormat::BF16_RN, tma::cudaTmaDescSwizzle::SWIZZLE_128B);
177	
178	    tma::cudaSetTmaTileDescriptor(&desc_partial_o, (void*)per_batch_partial_o_ptr, DIMS_QKV,
179	                                  tensor_size_partial_o.data(), tensor_stride_partial_o.data(),
180	                                  tensor_traversal_stride_qkv.data(),
181	                                  tensor_box_size_partial_o.data(), tma::cudaTmaDescFormat::F32_RN,
182	                                  tma::cudaTmaDescSwizzle::SWIZZLE_128B);
183	
184	    reinterpret_cast<tma::cudaTmaDesc*>(tma_desc_q_array)[i] = desc_q;
185	    reinterpret_cast<tma::cudaTmaDesc*>(tma_desc_o_array)[i] = desc_o;
186	    reinterpret_cast<tma::cudaTmaDesc*>(tma_desc_partial_o_array)[i] = desc_partial_o;
187	
188	    batch_offset_qo += d * h_qo * BYTES_PER_ELEMENT;
189	    batch_offset_partial_o += d * h_qo * sizeof(float);
190	  }
191	}
