285	#pragma unroll 1
286	  for (int i = 0; i < b; ++i) {
287	    const uint32_t actual_s_q = static_cast<uint32_t>(actual_seq_lens_q_data[i]);
288	
289	    // batch_offset_qo = batch_offset_array ? batch_offset_array[i] : batch_offset_qo;
