517	void prefill(int64_t b, int64_t s_qo, int64_t max_s_kv, TensorView q, TensorView k_cache,
518	             TensorView v_cache, double scale, TensorView workspace_buffer,
519	             TensorView actual_seq_lens_q, TensorView actual_seq_lens_kv,
520	             TensorView actual_seq_lens_q_gpu, TensorView actual_seq_lens_kv_gpu,
521	             TensorView block_tables, bool causal, bool return_lse, TensorView out, TensorView lse,
522	             Optional<TensorView> batch_offset_q_array, Optional<TensorView> batch_offset_o_array,
523	             Optional<TensorView> batch_offset_k_array, Optional<TensorView> batch_offset_v_array,
524	             bool is_cuda_graph_compatible) {
525	  constexpr size_t SMEM_SIZE = 227 * 1024;  // All smem
526	  constexpr int64_t TILE_M_1 = 128;
527	  constexpr int64_t TILE_N_1 = 128;
528	
529	  constexpr int32_t NUM_THREADS = 512;
530	
531	  const CUstream stream = get_stream(q.device());
532	
533	  int64_t* batch_offset_q_array_data = nullptr;
534	  int64_t* batch_offset_o_array_data = nullptr;
535	  int64_t* batch_offset_k_array_data = nullptr;
536	  int64_t* batch_offset_v_array_data = nullptr;
537	  int64_t* batch_offset_array_data = nullptr;
538	  if (batch_offset_q_array.has_value()) {
539	    batch_offset_array_data = static_cast<int64_t*>(
540	        batch_offset_q_array.value().data_ptr());  // Fix this to make it operational later
541	  }
542	
543	  // Step 1: Setup the kernel pointer
544	
545	  static CUfunction prefill_func[KERNEL_NUM_PREFILL_TYPES] = {nullptr, nullptr, nullptr, nullptr};
546	
547	  int64_t d_qk = q.size(2);
548	
549	  int64_t d_vo = v_cache.ndim() == 3 ? v_cache.size(2) : v_cache.size(3);
550	
551	  if (prefill_func[0] == nullptr) {
552	    setup_prefill(prefill_func);
553	
554	    for (int i = 0; i < KERNEL_NUM_PREFILL_TYPES; i++) {
555	      if (prefill_func[i] != nullptr) {
556	        cuErrCheck(cuFuncSetAttribute(prefill_func[i],
557	                                      CU_FUNC_ATTRIBUTE_MAX_DYNAMIC_SHARED_SIZE_BYTES, SMEM_SIZE));
558	        cuErrCheck(cuFuncSetAttribute(prefill_func[i],
559	                                      CU_FUNC_ATTRIBUTE_PREFERRED_SHARED_MEMORY_CARVEOUT, 100));
560	        cuErrCheck(cuFuncSetAttribute(prefill_func[i],
561	                                      CU_FUNC_ATTRIBUTE_NON_PORTABLE_CLUSTER_SIZE_ALLOWED, 1));
562	      }
563	    }
564	  }
565	
566	  // Step 2: Extract attention descriptor
567	
568	  int64_t h_qo = q.size(1);
569	
570	  int64_t h_kv = k_cache.size(1);
571	
572	  int64_t page_size = k_cache.ndim() == 4 ? k_cache.size(2) : 1;
573	
574	  int64_t s_kv = max_s_kv;
575	
576	  int64_t num_pages_per_seq = static_cast<int64_t>(std::ceil(1.0 * s_kv / page_size));
577	
578	  int64_t total_num_pages = k_cache.ndim() == 4 ? k_cache.size(0) : 1;
579	
580	  bool kv_cache_enabled = d_qk == 192 ? false : true;
581	
582	  // Step 3: Setup the launch configuration
583	
584	  CUlaunchConfig config;
585	
586	  constexpr int NUM_ATTRS = 1;
587	  CUlaunchAttribute attrs[NUM_ATTRS];
588	  config.numAttrs = NUM_ATTRS;
589	  attrs[0].id = CU_LAUNCH_ATTRIBUTE_CLUSTER_DIMENSION;
590	  attrs[0].value.clusterDim.x = 1;
591	  attrs[0].value.clusterDim.y = 1;
592	  attrs[0].value.clusterDim.z = 1;
593	  config.attrs = attrs;
594	
595	  config.sharedMemBytes = SMEM_SIZE;
596	  config.hStream = stream;
597	
598	  if (is_cuda_graph_compatible == false) {
599	    CHECK_CPU(actual_seq_lens_q);
600	    CHECK_CPU(actual_seq_lens_kv);
601	    auto actual_seq_lens_q_data = static_cast<int32_t*>(actual_seq_lens_q.data_ptr());
602	    auto actual_seq_lens_kv_data = static_cast<int32_t*>(actual_seq_lens_kv.data_ptr());
603	
604	    uint32_t actual_num_tiles_per_head = std::transform_reduce(
605	        actual_seq_lens_q_data, actual_seq_lens_q_data + b, 0U, std::plus<>(), [](int32_t seq_len) {
606	          return static_cast<uint32_t>(std::ceil(seq_len / (TILE_M_1 * 2.0f)));
607	        });
608	    config.gridDimX = actual_num_tiles_per_head;
609	
610	  } else {
611	    config.gridDimX = static_cast<int>(std::ceil(s_qo / (TILE_M_1 * 2.0f))) * b;
612	  }
