661	      reinterpret_cast<tma::cudaTmaDesc*>(workspace_start + sizeof(tma::cudaTmaDesc) * (2 * b));
662	  tma::cudaTmaDesc* tma_desc_v =
663	      reinterpret_cast<tma::cudaTmaDesc*>(workspace_start + sizeof(tma::cudaTmaDesc) * (3 * b));
664	
665	  if (is_cuda_graph_compatible == false) {
