700	    }
701	
702	    qkv_tma_setup_prefill<<<grid, block, 0, raw_stream>>>(
703	        b, h_qo, h_kv, d_qk, d_vo, is_kv_ragged, page_size, total_num_pages, k_cache.stride(2),
704	        k_cache.stride(1), k_cache.stride(0), v_cache.stride(2), v_cache.stride(1),
