748	  };
749	
750	  // for (int i = 0; i < b; i++) {
751	  //   print_cudaTmaDescTiled(reinterpret_cast<tma::cudaTmaDescTiled*>(&packed_tma_desc_q[i]));
752	  //   print_cudaTmaDescTiled(reinterpret_cast<tma::cudaTmaDescTiled*>(&packed_tma_desc_o[i]));
753	  // }
754	  // print_cudaTmaDescTiled(reinterpret_cast<tma::cudaTmaDescTiled*>(tma_desc_v_host));
755	
756	  void* args[14];
757	  args[0] = (void*)&attn_desc;
758	  args[1] = (void*)&packed_tma_desc_q_dev;
759	  args[2] = (void*)&tma_desc_k;
760	  args[3] = (void*)&attn_scale;
761	  args[4] = &lse_tensor_pointer;
762	  args[5] = (void*)&lse_strides;
763	  args[6] = (void*)&tma_desc_v;
764	  args[7] = (void*)&packed_tma_desc_o_dev;
765	  args[8] = &actual_seq_lens_q_gpu_pointer;
766	  args[9] = &actual_seq_lens_kv_gpu_pointer;
