790	static int32_t compute_split_factor(int32_t b, int32_t h_kv, int32_t h_qo, int32_t s_kv,
791	                                    uint32_t sm_count) {
792	  uint32_t split_factor = 1;
793	  if ((b * h_kv <= (sm_count / 2))) {
794	    split_factor = std::ceil(1.f * sm_count / (b * h_kv));
795	    int i = 2;
796	    for (; i < 128; i *= 2) {
797	      if (split_factor <= (i + (i / 2) + (i / 4))) {
798	        split_factor = i;
799	        break;
800	      }
801	    }
802	    if (i == 128) {
803	      split_factor = 64;
804	    }
805	    if ((h_qo / h_kv) <= 8) {
806	      while (std::ceil(1.f * s_kv / split_factor) < (h_qo / h_kv)) {
807	        split_factor /= 2;
808	      }
809	      if (s_kv <= 512) {
810	        split_factor = 1;
811	      }
812	    } else {
813	      if (s_kv <= 1024) {
814	        split_factor = 1;
815	      }
816	    }
817	    if (split_factor == 0) {
818	      split_factor = 1;
819	    }
820	  }
821	  return split_factor;
822	}
