824	int32_t get_kernel_id(int32_t q_heads_per_kv) {
825	  auto kernel_id = 0;
826	  if (q_heads_per_kv == 1) {
827	    kernel_id = 0;
828	  } else if (q_heads_per_kv <= 8) {
829	    kernel_id = 1;
830	  } else if (q_heads_per_kv <= 16) {
831	    kernel_id = 2;
832	  } else if (q_heads_per_kv <= 32) {
833	    kernel_id = 3;
834	  } else {
835	    kernel_id = 4;
836	  }
837	  return kernel_id;
838	}
