840	void setup_tma_desc_decode(int64_t b, int64_t s_kv, int64_t h_qo, int64_t h_kv, int64_t d,
841	                           int64_t total_num_pages, TensorView q, TensorView out,
842	                           TensorView k_cache, TensorView v_cache, int32_t split_factor,
843	                           int64_t page_size, int8_t* partial_o_dev, tma::cudaTmaDesc* tma_desc_q,
844	                           tma::cudaTmaDesc* tma_desc_o, tma::cudaTmaDesc* tma_desc_partial_o,
845	                           tma::cudaTmaDesc* tma_desc_k, tma::cudaTmaDesc* tma_desc_v) {
846	  auto kid = get_kernel_id(h_qo / h_kv);
847	  int64_t TILE_M_1 = 1;
848	  int64_t TILE_N_1 = 128;
849	  switch (kid) {
850	    case 0:
851	      TILE_M_1 = 1;
852	      break;
853	    case 1:
854	      TILE_M_1 = 8;
855	      break;
856	    case 2:
857	      TILE_M_1 = 16;
858	      break;
859	    case 3:
860	      TILE_M_1 = 32;
861	      break;
862	    case 4:
863	      TILE_M_1 = 64;
864	      break;
